sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var result = {
        status: "success",
        entity_records: []
    };

    try {
        var tableSysId = request.queryParams.entity_type_sys_id
            ? String(request.queryParams.entity_type_sys_id[0])
            : null;

        if (!tableSysId) {
            response.setStatus(400);
            return { status: "error", message: "Missing required fields: entity_type_sys_id" };
        }

        // Get the Table Name from the sys_id provided
        var tableDefGR = new GlideRecord('sys_db_object');
        if (!tableDefGR.get(tableSysId)) {
            response.setStatus(404);
            return { status: "error", message: "Table definition not found for the provided sys_id." };
        }
        var actualTableName = tableDefGR.name.toString();

        // Get the display field for this table
        var tempGR = new GlideRecord(actualTableName);
        tempGR.initialize();
        var displayFieldName = tempGR.getDisplayName();

        // Parse labels — queryParams.label is already an array when sent multiple times
        var labels = [];
        if (request.queryParams.label) {
            for (var i = 0; i < request.queryParams.label.length; i++) {
                var trimmed = String(request.queryParams.label[i]).trim();
                if (trimmed) labels.push(trimmed);
            }
        }

        var limit = 100;
        var excludeSysIds = [];

        if (labels.length > 0) {
            // Query 1: All exact matches for any of the labels
            var exactGR = new GlideRecord(actualTableName);
            exactGR.addQuery(displayFieldName, 'IN', labels.join(','));
            exactGR.orderBy(displayFieldName);
            exactGR.query();

            while (exactGR.next()) {
                excludeSysIds.push(exactGR.getUniqueValue());
                result.entity_records.push({
                    label: exactGR.getDisplayValue(),
                    sys_id: exactGR.getUniqueValue(),
                });
            }

            // Query 2: Fill remaining slots with CONTAINS matches
            var remaining = limit - result.entity_records.length;
            if (remaining > 0) {
                var containsGR = new GlideRecord(actualTableName);
                var orCondition = containsGR.addQuery(displayFieldName, 'CONTAINS', labels[0]);
                for (var j = 1; j < labels.length; j++) {
                    orCondition.addOrCondition(displayFieldName, 'CONTAINS', labels[j]);
                }
                if (excludeSysIds.length > 0) {
                    containsGR.addQuery('sys_id', 'NOT IN', excludeSysIds.join(','));
                }
                containsGR.orderBy(displayFieldName);
                containsGR.setLimit(remaining);
                containsGR.query();

                while (containsGR.next()) {
                    result.entity_records.push({
                        label: containsGR.getDisplayValue(),
                        sys_id: containsGR.getUniqueValue(),
                    });
                }
            }

        } else {
            var defaultGR = new GlideRecord(actualTableName);
            defaultGR.orderBy(displayFieldName);
            defaultGR.setLimit(limit);
            defaultGR.query();

            while (defaultGR.next()) {
                result.entity_records.push({
                    label: defaultGR.getDisplayValue(),
                    sys_id: defaultGR.getUniqueValue(),
                });
            }
        }

        response.setStatus(200);
        return result;

    } catch (e) {
        response.setStatus(400);
        return { status: "error", message: e.toString() };
    }
})(request, response);
